1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	  contractCount: number;
11	}
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	const INSURANCE_VALUES: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	};
28	
29	const BLOCK_PRICE_FOR_3_ALIKE = 60;
30	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
31	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
32	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
33	const FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER = 0.85;
34	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
35	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const FOLLOW_UP_CONTRACT_MIN_COUNT = 1;
38	
39	interface Policy {
40	  basePremium: number;
41	  premium: number;
42	  items: Item[];
43	  insuranceSum: number;
44	  remainingCap: number;
45	}
46	
47	const roundToCents = (amount: number): number => Math.round(amount * 100) / 100;
48	
49	const PROCESSING_FEE = 5;
50	
51	const calculateItemCosts = (items: Item[]): number => {
52	  const nonCursedCountsByType: Record<string, number> = {};
53	  let cursedCost = 0;
54	  let enchantmentSurcharge = 0;
55	
56	  for (const item of items) {
57	    const itemBasePremium = BASE_PREMIUMS[item.type];
58	    if (item.cursed) {
59	      cursedCost += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
60	    } else {
61	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
62	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
63	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
64	      }
65	    }
66	  }
67	
68	  let nonCursedCost = 0;
69	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
70	    if (count === 3) {
71	      nonCursedCost += BLOCK_PRICE_FOR_3_ALIKE;
72	    } else {
73	      nonCursedCost += count * BASE_PREMIUMS[type];
74	    }
75	  }
76	
77	  return cursedCost + nonCursedCost + enchantmentSurcharge;
78	};
79	
80	export function generateQuote(items: Item[], customer: Customer): Policy {
81	  const followUpMultiplier = customer.contractCount >= FOLLOW_UP_CONTRACT_MIN_COUNT ? FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER : 1;
82	  const loyaltyMultiplier = customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS ? LOYALTY_DISCOUNT_MULTIPLIER : 1;
83	  const basePremium = roundToCents(calculateItemCosts(items) * FIRST_INSURANCE_SURCHARGE_MULTIPLIER * followUpMultiplier * loyaltyMultiplier);
84	  const insuranceSum = items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
85	  const remainingCap = 2 * insuranceSum;
86	  return { basePremium, premium: Math.ceil(basePremium + PROCESSING_FEE), items, insuranceSum, remainingCap };
87	}
