89	const DEDUCTIBLE = 100;
90	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
91	const HIGH_ENCHANTMENT_PAYOUT_MULTIPLIER = 0.5;
92	
93	interface Damage {
94	  itemType: string;
95	  amount: number;
96	}
97	
98	interface Incident {
99	  cause: string;
100	  damages: Damage[];
101	}
102	
103	const applyEnchantmentReduction = (amount: number, enchantment: number): number =>
104	  enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
105	    ? amount * HIGH_ENCHANTMENT_PAYOUT_MULTIPLIER
106	    : amount;
107	
108	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
109	  const damage = incident.damages[0];
110	  const item = policy.items.find((i) => i.type === damage.itemType);
111	  const enchantment = item?.enchantment ?? 0;
112	  const effectiveDamage = applyEnchantmentReduction(damage.amount, enchantment);
113	  const payoutBeforeCap = Math.max(0, effectiveDamage - DEDUCTIBLE);
114	  const payout = Math.min(payoutBeforeCap, policy.remainingCap);
115	  return { payout, remainingCap: policy.remainingCap - payout };
116	}
